SELECT CH.SEMESTRE FROM CALC_HORA_AULA_MEDIA CH JOIN SERVIDOR S ON S.PK_SIAPE=CH.SIAPE WHERE CH.ANO=2023 AND CH.SIGLA_CAMPUS='OES' AND LOWER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%matem%' AND UPPER(COALESCE(S.CONTRATO,''))='EFETIVOS' GROUP BY CH.SEMESTRE HAVING COUNT(DISTINCT CH.SIAPE)=1 ORDER BY CH.SEMESTRE